package attribute

import (
	"fmt"
	"log/slog"

	bgpctx "codeberg.org/thomas-mangin/ze/internal/plugin/bgp/context"
	"codeberg.org/thomas-mangin/ze/internal/plugin/bgp/wire"
)

// Origin represents the ORIGIN path attribute.
//
// RFC 4271 Section 4.3 (UPDATE Message Format):
//
//	"ORIGIN is a well-known mandatory attribute that defines the
//	origin of the path information."
//
// RFC 4271 Section 5.1.1 (ORIGIN):
//
//	"ORIGIN is a well-known mandatory attribute. The ORIGIN attribute is
//	generated by the speaker that originates the associated routing
//	information. Its value SHOULD NOT be changed by any other speaker."
//
// The attribute value is a single octet (1 byte).
type Origin uint8

// Origin values as defined in RFC 4271 Section 4.3:
//
//	Value   Meaning
//	0       IGP - Network Layer Reachability Information is interior to the originating AS
//	1       EGP - Network Layer Reachability Information learned via the EGP protocol [RFC904]
//	2       INCOMPLETE - Network Layer Reachability Information learned by some other means
const (
	OriginIGP        Origin = 0 // RFC 4271: interior to the originating AS
	OriginEGP        Origin = 1 // RFC 4271: learned via EGP [RFC904]
	OriginIncomplete Origin = 2 // RFC 4271: learned by some other means
)

var originNames = map[Origin]string{
	OriginIGP:        "IGP",
	OriginEGP:        "EGP",
	OriginIncomplete: "INCOMPLETE",
}

// String returns the human-readable origin name ("IGP", "EGP", or "INCOMPLETE").
func (o Origin) String() string {
	if name, ok := originNames[o]; ok {
		return name
	}
	return fmt.Sprintf("UNKNOWN(%d)", o)
}

// Code returns AttrOrigin (Type Code 1 per RFC 4271 Section 4.3).
func (o Origin) Code() AttributeCode { return AttrOrigin }

// Flags returns FlagTransitive.
//
// RFC 4271 Section 4.3: "ORIGIN is a well-known mandatory attribute"
// Well-known attributes have the Transitive bit set.
func (o Origin) Flags() AttributeFlags { return FlagTransitive }

// Len returns 1.
//
// RFC 4271 Section 4.3: "The data octet can assume the following values"
// The ORIGIN attribute is always exactly 1 octet.
func (o Origin) Len() int { return 1 }

// Pack serializes the origin value as a single octet per RFC 4271.
func (o Origin) Pack() []byte { return []byte{byte(o)} }

// PackWithContext returns Pack() - ORIGIN encoding is context-independent.
func (o Origin) PackWithContext(_, _ *bgpctx.EncodingContext) []byte { return o.Pack() }

// WriteTo writes the origin value into buf at offset.
// Returns 1 (number of bytes written).
func (o Origin) WriteTo(buf []byte, off int) int {
	buf[off] = byte(o)
	return 1
}

// WriteToWithContext writes the origin value - context-independent.
func (o Origin) WriteToWithContext(buf []byte, off int, _, _ *bgpctx.EncodingContext) int {
	return o.WriteTo(buf, off)
}

// CheckedWriteTo validates capacity before writing.
// Returns ErrBufferTooSmall if buffer is insufficient.
func (o Origin) CheckedWriteTo(buf []byte, off int) (int, error) {
	if len(buf) < off+1 {
		return 0, wire.ErrBufferTooSmall
	}
	return o.WriteTo(buf, off), nil
}

// ParseOrigin parses an ORIGIN attribute value.
//
// RFC 4271 Section 6.3 (UPDATE Message Error Handling):
//
//	"If the ORIGIN attribute has an undefined value, then the Error Sub-
//	code MUST be set to Invalid Origin Attribute. The Data field MUST
//	contain the unrecognized attribute (type, length, and value)."
//
// Valid values are 0 (IGP), 1 (EGP), and 2 (INCOMPLETE) per Section 4.3.
func ParseOrigin(data []byte) (Origin, error) {
	if len(data) < 1 {
		return 0, ErrShortData
	}
	o := Origin(data[0])
	// RFC 4271 Section 6.3: undefined values trigger Invalid Origin Attribute error
	if o > OriginIncomplete {
		return 0, fmt.Errorf("%w: invalid origin value %d", ErrMalformedValue, o)
	}
	return o, nil
}

// PackAttribute packs an attribute with its header.
//
// Deprecated: Use WriteAttrTo for zero-allocation encoding.
func PackAttribute(attr Attribute) []byte {
	value := attr.Pack()
	header := PackHeader(attr.Flags(), attr.Code(), uint16(len(value))) //nolint:gosec // Attr max 65535
	return append(header, value...)
}

// PackASPathAttribute packs an AS_PATH attribute with optional 4-byte ASN support.
//
// Deprecated: Use WriteAttrTo with ASPath for zero-allocation encoding.
func PackASPathAttribute(asPath *ASPath, asn4 bool) []byte {
	value := asPath.PackWithASN4(asn4)
	header := PackHeader(asPath.Flags(), asPath.Code(), uint16(len(value))) //nolint:gosec // Attr max 65535
	return append(header, value...)
}

// OrderAttributes sorts attributes by type code per RFC 4271 Appendix F.3.
//
// RFC 4271 Appendix F.3 - Path Attribute Ordering:
//
//	"It is a useful optimization to order the path attributes according
//	 to type code. This optimization is entirely optional."
//
// The function returns a new slice; the original is not modified.
// If the input is nil, nil is returned.
// If the input is empty, an empty slice is returned.
func OrderAttributes(attrs []Attribute) []Attribute {
	if attrs == nil {
		return nil
	}
	if len(attrs) == 0 {
		return []Attribute{}
	}
	if len(attrs) == 1 {
		return attrs
	}

	// Create a copy to avoid modifying the original
	sorted := make([]Attribute, len(attrs))
	copy(sorted, attrs)

	// Sort by type code using insertion sort (stable, good for small slices)
	for i := 1; i < len(sorted); i++ {
		key := sorted[i]
		j := i - 1
		for j >= 0 && sorted[j].Code() > key.Code() {
			sorted[j+1] = sorted[j]
			j--
		}
		sorted[j+1] = key
	}

	return sorted
}

// PackAttributesOrdered packs a slice of attributes ordered by type code.
//
// RFC 4271 Appendix F.3: Order by type code for efficient comparison.
// This combines OrderAttributes and PackAttribute for convenience.
//
// Deprecated: Use WriteAttributesOrdered for zero-allocation encoding.
func PackAttributesOrdered(attrs []Attribute) []byte {
	if len(attrs) == 0 {
		return nil
	}

	ordered := OrderAttributes(attrs)

	// Calculate total size
	totalLen := 0
	for _, attr := range ordered {
		// Header (3 or 4 bytes) + value
		attrLen := attr.Len()
		if attrLen > 255 {
			totalLen += 4 + attrLen // Extended length header
		} else {
			totalLen += 3 + attrLen // Normal header
		}
	}

	// Pack all attributes using copy (single allocation)
	buf := make([]byte, totalLen)
	off := 0
	for _, attr := range ordered {
		off += WriteAttrTo(attr, buf, off)
	}

	// Sanity check: verify size calculation matches actual bytes written
	if off != totalLen {
		slog.Error("attribute size mismatch: Len disagrees with WriteTo",
			"predicted", totalLen,
			"actual", off,
			"attrCount", len(attrs))
		// Return actual bytes written to maintain correctness
		return buf[:off]
	}

	return buf
}

// WriteAttributesOrdered writes attributes ordered by type code into buf.
// Returns the number of bytes written.
//
// RFC 4271 Appendix F.3: Order by type code for efficient comparison.
// Zero-allocation: writes directly into provided buffer.
func WriteAttributesOrdered(attrs []Attribute, buf []byte, off int) int {
	if len(attrs) == 0 {
		return 0
	}

	ordered := OrderAttributes(attrs)
	start := off
	for _, attr := range ordered {
		off += WriteAttrTo(attr, buf, off)
	}

	return off - start
}

// AttributesSize calculates the total wire size of attributes (header + value).
// Used for pre-allocating buffers before calling WriteAttributesOrdered.
func AttributesSize(attrs []Attribute) int {
	totalLen := 0
	for _, attr := range attrs {
		attrLen := attr.Len()
		if attrLen > 255 {
			totalLen += 4 + attrLen // Extended length header
		} else {
			totalLen += 3 + attrLen // Normal header
		}
	}
	return totalLen
}

// AttributesSizeWithContext calculates the total wire size with context-dependent encoding.
// Context affects AS_PATH (ASN4 encoding) and AGGREGATOR (6 vs 8 byte format).
// Used for pre-allocating buffers before calling WriteAttrToWithContext.
func AttributesSizeWithContext(attrs []Attribute, ctx *bgpctx.EncodingContext) int {
	totalLen := 0
	for _, attr := range attrs {
		attrLen := attrLenWithContext(attr, ctx)
		if attrLen > 255 {
			totalLen += 4 + attrLen // Extended length header
		} else {
			totalLen += 3 + attrLen // Normal header
		}
	}
	return totalLen
}
